package com.chaobo.scm.purchase.application.integration;
import com.chaobo.scm.purchase.infrastructure.persistence.integration.IntegrationCommandMapper;import org.springframework.beans.factory.annotation.Value;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.PlatformTransactionManager;import org.springframework.transaction.support.TransactionTemplate;import java.time.OffsetDateTime;import java.util.List;
@Service public class PurchaseIntegrationCommandDispatcher {private final IntegrationCommandMapper mapper;private final TransactionTemplate tx;private final int batch,max;public PurchaseIntegrationCommandDispatcher(IntegrationCommandMapper mapper,PlatformTransactionManager manager,@Value("${scm.integration.batch-size:50}")int batch,@Value("${scm.integration.max-retries:8}")int max){this.mapper=mapper;this.tx=new TransactionTemplate(manager);this.batch=batch;this.max=max;}@Scheduled(fixedDelayString="${scm.integration.fixed-delay:1000}")public void dispatch(){List<IntegrationCommandMapper.CommandRow> rows=tx.execute(s->mapper.lockDispatchable(batch).stream().filter(v->mapper.markExecuting(v.commandId())==1).toList());if(rows!=null)rows.forEach(this::send);}private void send(IntegrationCommandMapper.CommandRow row){try{throw new IllegalStateException("尚未注册目标系统防腐层: "+row.targetSystem()+"/"+row.commandType());}catch(RuntimeException e){String r=e.getMessage();tx.executeWithoutResult(s->mapper.markRetry(row.commandId(),row.retryCount(),OffsetDateTime.now().plusSeconds(Math.min(300,1L<<Math.min(8,row.retryCount()))),r==null?e.getClass().getSimpleName():r.substring(0,Math.min(1000,r.length())),max));}}}
